from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetLatestProductPathNode(BaseNode):
    name = "Prism: Get Latest Product Path"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_input("product_name", "string", widget_type="text")
        self.add_output("version_path", "string")
        self.add_output("found", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get('entity') or {}
        prod = inputs.get('product_name') or ''
        if core is None:
            self.log_error("No PrismCore provided.")
            return {'version_path': '', 'found': False}
        try:
            path = ''
            fn_names = ('getLatestVersionFromProduct', 'getLatestVersion', 'getLatestVersionPath')
            for fn_name in fn_names:
                if hasattr(core.products, fn_name):
                    res = getattr(core.products, fn_name)(prod, entity)
                    # Some versions return a dict with 'path', others a string
                    if isinstance(res, dict):
                        path = res.get('path') or res.get('filepath') or ''
                    else:
                        path = str(res or '')
                    break
            found = bool(path)
            self.log_info(f"Latest version path: {path or '(none)'}")
            return {'version_path': path, 'found': found}
        except Exception as e:
            self.log_error(f"getLatestVersionFromProduct failed: {e}")
            return {'version_path': '', 'found': False}

def register_node():
    return PrismGetLatestProductPathNode
